import{_ as n,c as a,a as e,o as i}from"./app-CEcM0piI.js";const l={};function p(d,s){return i(),a("div",null,s[0]||(s[0]=[e(`<p>解决clion中qdebug不输出内容的方法 在调试配置-&gt;环境变量中添加以下代码</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>QT_ASSUME_STDERR_HAS_CONSOLE=1</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int main(int argc,char* argv[])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>argc：命令行变量的数量 argv：命令行变量的数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>return QApplication::exec();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>exec()是一个while循环，退出条件是点击关闭窗口。</p><p><mark>方法规律</mark> Qt中如果想要获取属性信息使用属性名的方法，如果要设置属性使用set+属性名 r+属性名获取属性的引用 进行操作的方法使用一般现代时的是无返回值，使用过去时的是有返回值的 这是Qt中API函数的特点 如果set+属性名的函数参数是只有一个布尔类型，把函数改为is+属性名就是这个属性的判定函数，如果不是布尔类型，把set去掉使用属性名调用函数的返回值就能显示这个属性处于什么状态 属性面板中的属性优先级低于代码中的属性</p><p>界面组件：</p><table><thead><tr><th>组件名</th><th>作用</th></tr></thead><tbody><tr><td>Layouts</td><td>布局</td></tr><tr><td>Spacers</td><td>弹簧，也用于布局</td></tr><tr><td>Buttons</td><td>按钮</td></tr><tr><td>Item Views（Model-Based）</td><td>视图控件（需要依赖一些模型），模型在Qt中主要用来存储数据的，主要目的是实现数据和显示的分离，经常用于数据量比较大的地方，主要用于数据库</td></tr><tr><td>Item Widgets（Item-Based）</td><td>对Item Views的简化，简单好用，缺点是不能实现视图和数据的分离</td></tr><tr><td>Containers</td><td>容器相关的窗口</td></tr><tr><td>Input Widgets</td><td>输入类型的窗口</td></tr><tr><td>Display Widgets</td><td>展示使用的窗口</td></tr></tbody></table><h2 id="qt中的模块" tabindex="-1"><a class="header-anchor" href="#qt中的模块"><span>Qt中的模块</span></a></h2><p>Qt类库里大量的类根据功能分为各种模块，这些模块又分为以下几大类：</p><ul><li>Qt 基本模块（Qt Essentials)：提供了 Qt 在所有平台上的基本功能。</li><li>Qt 附加模块（Qt Add-Ons)：实现一些特定功能的提供附加价值的模块。</li><li>增值模块（Value-AddModules)：单独发布的提供额外价值的模块或工具。</li><li>技术预览模块（Technology Preview Modules）：一些处于开发阶段，但是可以作为技术预览使用的模块。</li><li>Qt 工具（Qt Tools)：帮助应用程序开发的一些工具。</li></ul><p><mark>Qt的主要模块</mark> ![[Pasted image 20240301194522.png]]</p><h1 id="qapplication应用程序类" tabindex="-1"><a class="header-anchor" href="#qapplication应用程序类"><span>QApplication应用程序类</span></a></h1><p>在同名的头文件中 用于控制窗口的输入</p><h3 id="exec-阻塞函数" tabindex="-1"><a class="header-anchor" href="#exec-阻塞函数"><span>exec()阻塞函数</span></a></h3><p>调用这个函数程序并不会退出，程序进入事件循环</p><h1 id="窗口类" tabindex="-1"><a class="header-anchor" href="#窗口类"><span>窗口类</span></a></h1><p>![[Pasted image 20240301201706.png]] qt有三个窗口类：QWidget、QDialog、QMainWindow</p><h2 id="qwidget" tabindex="-1"><a class="header-anchor" href="#qwidget"><span>QWidget</span></a></h2><p>所有窗口类的基类</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MainWindow::MainWindow(QWidget *parent): QMainWindow(parent), ui(new Ui::MainWindow){</span></span>
<span class="line"><span>    ui-&gt;setupUi(this);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#if 0</span></span>
<span class="line"><span>    //一般在qt的构造函数中进行初始化操作（窗口、数据……）</span></span>
<span class="line"><span>    //显示当前窗口的时候，显示另外一个窗口TestWidget</span></span>
<span class="line"><span>    //创建窗口对象，没有给w对象指定父对象，就需要调用w的show()方法，而且弹出的w窗口是独立的</span></span>
<span class="line"><span>    TestWidget* w=new TestWidget;</span></span>
<span class="line"><span>    w-&gt;show();</span></span>
<span class="line"><span>#else</span></span>
<span class="line"><span>    //创建窗口对象，给w指定父对象</span></span>
<span class="line"><span>    //explicit TestWidget(QWidget* parent=null)</span></span>
<span class="line"><span>    //内嵌到父对象的窗口，不需要show()方法里面的元素就随父窗口一起弹出</span></span>
<span class="line"><span>    //这个时候子窗口就没有边框了</span></span>
<span class="line"><span>    TestWidget* w=new TestWidget(this);</span></span>
<span class="line"><span>#endif</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="qdialog" tabindex="-1"><a class="header-anchor" href="#qdialog"><span>QDialog</span></a></h2><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#if 0</span></span>
<span class="line"><span>//非模态</span></span>
<span class="line"><span>    //创建对话框窗口</span></span>
<span class="line"><span>    TestDialog* dlg=new TestDialog(this);//对话框窗口不管是指定父对象还是不指定父对象都不会内嵌到主窗口中</span></span>
<span class="line"><span>    dlg-&gt;show();//所以要show()方法才能显示</span></span>
<span class="line"><span>#else</span></span>
<span class="line"><span>//模态</span></span>
<span class="line"><span>    TestDialog* dlg=new TestDialog(this);</span></span>
<span class="line"><span>    //模态</span></span>
<span class="line"><span>    dlg-&gt;exec();</span></span>
<span class="line"><span>    //在取消阻塞模态对话框主窗口才会被构建出来，因为主窗口构造函数还没构造完成，阻塞在了当前位置</span></span>
<span class="line"><span>    //模态对话框在阻塞的时候是不能进行焦点切换的</span></span>
<span class="line"><span>    //模态对话框会阻塞程序的执行，不取消阻塞当前的窗口无法点击其他窗口</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="qmainwindow" tabindex="-1"><a class="header-anchor" href="#qmainwindow"><span>QMainWindow</span></a></h2><p>QMainWindow中菜单栏（menubar）和状态栏（statusbar）只能有一个，但工具栏（toolbar）可以有很多个</p><h2 id="qt的坐标体系" tabindex="-1"><a class="header-anchor" href="#qt的坐标体系"><span>Qt的坐标体系</span></a></h2><p><mark>Qt的坐标原点在窗口的左上角，x轴向右递增，y轴向下递增</mark></p><p>内嵌的子窗口的坐标体系是它父窗口的坐标系</p><h2 id="qpushbutton" tabindex="-1"><a class="header-anchor" href="#qpushbutton"><span>QPushButton</span></a></h2><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MainWindow::MainWindow(QWidget *parent)</span></span>
<span class="line"><span>    : QMainWindow(parent)</span></span>
<span class="line"><span>    , ui(new Ui::MainWindow)</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>    ui-&gt;setupUi(this);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    this-&gt;move(10,10);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    //创建一个按钮，让这个按钮作为当前创建的子控件</span></span>
<span class="line"><span>    QPushButton* btna=new QPushButton(this);</span></span>
<span class="line"><span>    //移动按钮的位置</span></span>
<span class="line"><span>    btna-&gt;move(10,10);</span></span>
<span class="line"><span>    //给按钮设置固定的大小</span></span>
<span class="line"><span>    btna-&gt;setFixedSize(200,200);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    //创建第二个按钮</span></span>
<span class="line"><span>    QPushButton* btnb=new QPushButton(btna);//作为btna的子窗口</span></span>
<span class="line"><span>    //移动按钮的位置</span></span>
<span class="line"><span>    btnb-&gt;move(10,10);</span></span>
<span class="line"><span>    //给按钮设置固定的大小</span></span>
<span class="line"><span>    btnb-&gt;setFixedSize(100,100);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    //创建第二个按钮</span></span>
<span class="line"><span>    QPushButton* btnc=new QPushButton(btnb);//作为btnb的子窗口</span></span>
<span class="line"><span>    //移动按钮的位置</span></span>
<span class="line"><span>    btnc-&gt;move(10,10);</span></span>
<span class="line"><span>    //给按钮设置固定的大小</span></span>
<span class="line"><span>    btnc-&gt;setFixedSize(50,50);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="qt的内存回收机制" tabindex="-1"><a class="header-anchor" href="#qt的内存回收机制"><span>Qt的内存回收机制</span></a></h2><p>在Qt中创建对象的时候会提供一个 <code>Parent对象指针</code>（可以查看类的构造函数），下面来解释这个parent到底是干什么的。</p><p>QObject是以对象树的形式组织起来的。<code>当你创建一个QObject对象时，会看到QObject的构造函数接收一个QObject指针作为参数，这个参数就是 parent，也就是父对象指针</code>。这相当于，在创建QObject对象时，可以提供一个其父对象，我们创建的这个QObject对象会自动添加到其父对象的children()列表。当父对象析构的时候，这个列表中的所有对象也会被析构。（注意，<code>这里的父对象并不是继承意义上的父类！</code>）</p><p>QWidget是能够在屏幕上显示的一切组件的父类。QWidget继承自QObject，因此也继承了这种对象树关系。一个孩子自动地成为父组件的一个子组件。因此，它会显示在父组件的坐标系统中，被父组件的边界剪裁。例如，当用户关闭一个对话框的时候，应用程序将其删除，那么，我们希望属于这个对话框的按钮、图标等应该一起被删除。事实就是如此，因为这些都是对话框的子组件。</p><p>Qt 引入对象树的概念，在一定程度上解决了内存问题。</p><ul><li><p>当一个QObject对象在堆上创建的时候，Qt 会同时为其创建一个对象树。不过，对象树中对象的顺序是没有定义的。这意味着，销毁这些对象的顺序也是未定义的。</p></li><li><p>任何对象树中的 QObject对象 delete 的时候，如果这个对象有 parent，则自动将其从 parent 的children()列表中删除；如果有孩子，则自动 delete 每一个孩子。Qt 保证没有QObject会被 delete 两次，这是由析构顺序决定的。 ![[Pasted image 20240304212236.png]] 综上所述, 我们可以得到一个结论: <code>Qt中有内存回收机制, 但是不是所有被new出的对象被自动回收, 满足条件才可以回收</code>, 如果想要在Qt中实现内存的自动回收, 需要满足以下两个条件:</p></li><li><p>创建的对象必须是QObject类的子类(间接子类也可以)</p><ul><li><p>QObject类是没有父类的, Qt中有很大一部分类都是从这个类派生出去的</p><ul><li>Qt中使用频率很高的窗口类和控件都是 QObject 的直接或间接的子类</li><li>其他的类可以自己查阅Qt帮助文档</li></ul></li></ul></li><li><p>创建出的类对象, 必须要指定其父对象是谁, 一般情况下有两种操作方式:</p></li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>// 方式1: 通过构造函数  </span></span>
<span class="line"><span>// parent: 当前窗口的父对象, 找构造函数中的 parent 参数即可  </span></span>
<span class="line"><span>QWidget::QWidget(QWidget *parent = Q_NULLPTR, Qt::WindowFlags f = Qt::WindowFlags());  </span></span>
<span class="line"><span>QTimer::QTimer(QObject *parent = nullptr);  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>// 方式2: 通过setParent()方法  </span></span>
<span class="line"><span>// 假设这个控件没有在构造的时候指定符对象, 可以调用QWidget的api指定父窗口对象  </span></span>
<span class="line"><span>void QWidget::setParent(QWidget *parent);  </span></span>
<span class="line"><span>void QObject::setParent(QObject *parent);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,38)]))}const c=n(l,[["render",p]]),r=JSON.parse('{"path":"/cpp/qt/1/","title":"1 简介","lang":"zh-CN","frontmatter":{"title":"1 简介","createTime":"2025/06/22 10:38:34","permalink":"/cpp/qt/1/"},"readingTime":{"minutes":6.85,"words":2055},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/Qt/1 简介.md","headers":[]}');export{c as comp,r as data};
